import{_ as e,a as t,b as l,c as o}from"./chunks/下载好后的视频.pSSnkGgz.js";import{_ as i,o as r,c as n,a2 as d}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Magnet Transfer","description":"","frontmatter":{},"headers":[],"relativePath":"hi/Other/magnet-transfer.md","filePath":"hi/Other/magnet-transfer.md","lastUpdated":1781962217000}'),s={name:"hi/Other/magnet-transfer.md"};function p(c,a,h,m,u,g){return r(),n("div",null,[...a[0]||(a[0]=[d('<h1 id="magnet-transfer" tabindex="-1">Magnet Transfer <a class="header-anchor" href="#magnet-transfer" aria-label="Permalink to &quot;Magnet Transfer&quot;">​</a></h1><p>Magnet transfer magnet link से files download करता है और उन्हें आपके चुने हुए cloud storage channel पर automatically upload कर देता है।</p><p>यह anime episodes, videos, archives और similar files transfer करने के लिए उपयोगी है। Magnet link paste करें, ImgBed background download task बनाता है। Download पूरा होने के बाद file ImgBed पर upload होती है और final link upload list में दिखता है।</p><p><img src="'+e+'" alt="Magnet transfer" loading="lazy"></p><h2 id="कहाँ-इस्तेमाल-करें" tabindex="-1">कहाँ इस्तेमाल करें <a class="header-anchor" href="#कहाँ-इस्तेमाल-करें" aria-label="Permalink to &quot;कहाँ इस्तेमाल करें&quot;">​</a></h2><p>Magnet transfer entry homepage upload area में होती है।</p><p>Magnet link input box में paste करें, <code>Transfer</code> चुनें, फिर upload करें।</p><p><img src="'+t+'" alt="Upload anime" loading="lazy"></p><h2 id="पहली-बार-इस्तेमाल-से-पहले" tabindex="-1">पहली बार इस्तेमाल से पहले <a class="header-anchor" href="#पहली-बार-इस्तेमाल-से-पहले" aria-label="Permalink to &quot;पहली बार इस्तेमाल से पहले&quot;">​</a></h2><p>पहले admin panel में magnet transfer configure करें।</p><p>आम तौर पर आपको चाहिए:</p><ol><li>Download task चलाने के लिए GitHub account।</li><li>Cloud upload channel, जैसे Google Drive या OneDrive।</li><li>Target upload directory।</li><li>Task timeout।</li></ol><p>Settings ready होने के बाद homepage पर लौटें और transfer शुरू करने के लिए magnet link paste करें।</p><h2 id="magnet-link-upload-करना" tabindex="-1">Magnet Link Upload करना <a class="header-anchor" href="#magnet-link-upload-करना" aria-label="Permalink to &quot;Magnet Link Upload करना&quot;">​</a></h2><ol><li>Homepage upload box में magnet link paste करें।</li><li>Confirm करें कि mode <code>Transfer</code> है।</li><li>Upload click करें।</li><li>ImgBed द्वारा magnet task create करने का इंतज़ार करें।</li><li>Task start होने के बाद progress देखने के लिए bottom-right corner वाला <code>Magnet Tasks</code> floating panel इस्तेमाल करें।</li></ol><p>Download और upload में समय लग सकता है। Speed magnet resource, GitHub runtime environment और selected cloud storage channel पर depend करती है।</p><p><img src="'+l+'" alt="Magnet downloading" loading="lazy"></p><h2 id="completion-के-बाद" tabindex="-1">Completion के बाद <a class="header-anchor" href="#completion-के-बाद" aria-label="Permalink to &quot;Completion के बाद&quot;">​</a></h2><p>Task complete होने पर upload list file name और link दिखाती है।</p><p>Videos में video preview, images में image preview, और other files में regular file icon दिखता है।</p><p><img src="'+o+'" alt="Downloaded video" loading="lazy"></p><p>आप copy कर सकते हैं:</p><table tabindex="0"><thead><tr><th>Link Type</th><th>Use Case</th></tr></thead><tbody><tr><td>Original link</td><td>Direct file access</td></tr><tr><td>Markdown</td><td>Markdown posts या notes</td></tr><tr><td>HTML</td><td>Web page code</td></tr><tr><td>BBCode</td><td>BBCode support करने वाले forums</td></tr></tbody></table><h2 id="magnet-task-panel" tabindex="-1">Magnet Task Panel <a class="header-anchor" href="#magnet-task-panel" aria-label="Permalink to &quot;Magnet Task Panel&quot;">​</a></h2><p>Bottom-right magnet task panel task count, task name, progress और final status दिखाता है।</p><p>Common states:</p><table tabindex="0"><thead><tr><th>Status</th><th>Meaning</th></tr></thead><tbody><tr><td>Waiting</td><td>Task created है और run होने का इंतज़ार कर रहा है।</td></tr><tr><td>Downloading</td><td>Magnet resource download हो रहा है।</td></tr><tr><td>Uploading</td><td>File download हो चुकी है और cloud storage पर upload हो रही है।</td></tr><tr><td>Completed</td><td>Upload successful है और link copy किया जा सकता है।</td></tr><tr><td>Failed</td><td>Task successful finish नहीं हुआ। Message check करें और फिर कोशिश करें।</td></tr></tbody></table><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>अगर magnet link में multiple files हैं, तो ImgBed display के लिए मुख्य completed file को priority देता है।</li><li>Large files में ज़्यादा समय लगेगा। Page refresh करने से पहले task finish होने दें।</li><li>अगर magnet resource के available peers नहीं हैं, तो download बहुत slow हो सकता है या fail हो सकता है।</li><li>Cloud account quota खत्म हो, authorization expired हो, या upload directory गलत हो, तो task fail हो सकता है।</li><li>Upload complete होने के बाद video preview दिखने में कुछ seconds लग सकते हैं।</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="magnet-link-paste-करने-के-बाद-कुछ-start-नहीं-हो-रहा" tabindex="-1">Magnet Link paste करने के बाद कुछ start नहीं हो रहा <a class="header-anchor" href="#magnet-link-paste-करने-के-बाद-कुछ-start-नहीं-हो-रहा" aria-label="Permalink to &quot;Magnet Link paste करने के बाद कुछ start नहीं हो रहा&quot;">​</a></h3><p>Confirm करें कि admin panel में magnet transfer enabled है और usable GitHub account तथा cloud channel selected हैं।</p><h3 id="download-हमेशा-slow-है" tabindex="-1">Download हमेशा slow है <a class="header-anchor" href="#download-हमेशा-slow-है" aria-label="Permalink to &quot;Download हमेशा slow है&quot;">​</a></h3><p>Magnet speed resource पर depend करती है। अगर available peers नहीं हैं, तो download बहुत slow या impossible हो सकता है।</p><h3 id="upload-के-बाद-preview-नहीं-दिख-रहा" tabindex="-1">Upload के बाद Preview नहीं दिख रहा <a class="header-anchor" href="#upload-के-बाद-preview-नहीं-दिख-रहा" aria-label="Permalink to &quot;Upload के बाद Preview नहीं दिख रहा&quot;">​</a></h3><p>पहले confirm करें कि file link खुल रहा है। Video files को browser में load होने में थोड़ा समय लग सकता है, या आप link direct खोल सकते हैं।</p><h3 id="task-fail-हो-तो-क्या-check-करें" tabindex="-1">Task fail हो तो क्या check करें? <a class="header-anchor" href="#task-fail-हो-तो-क्या-check-करें" aria-label="Permalink to &quot;Task fail हो तो क्या check करें?&quot;">​</a></h3><p>Magnet link valid है या नहीं, cloud channel काम कर रहा है या नहीं, और upload directory सही है या नहीं, यह check करें। फिर task दोबारा submit करें।</p>',38)])])}const w=i(s,[["render",p]]);export{b as __pageData,w as default};
